function formatExcerpt(text) {
  return text.length > 150 ? text.slice(0, 150) + '...' : text;
}

export default function Blog() {
  const [expandedId, setExpandedId] = useState(null);

  const togglePost = (id) => {
    setExpandedId(expandedId === id ? null : id);
  };

  return (
    <div className="w-full">
      <Helmet>
        <title>Blog | GOPPE Go</title>
        <meta name="description" content="Insights on education, AI, and innovation from GOPPE Go — helping educators and businesses thrive." />
        <meta property="og:title" content="Blog | GOPPE Go" />
        <meta property="og:description" content="Insights on education, AI, and innovation from GOPPE Go." />
        <meta property="og:type" content="website" />
        <meta property="og:url" content="https://goppego.org/blog" />
        <meta name="twitter:card" content="summary_large_image" />
        <meta name="twitter:title" content="Blog | GOPPE Go" />
        <meta name="twitter:description" content="Insights on education, AI, and innovation from GOPPE Go." />
      </Helmet>

      {/* Hero Section */}
      <section className="bg-slate-900 text-white py-20 px-4 sm:px-6 lg:px-8">
        <div className="max-w-4xl mx-auto text-center">
          <h1
            className="text-5xl sm:text-6xl font-bold mb-6"
            style={{ fontFamily: "'Playfair Display', Georgia, serif" }}
          >
            The Blog
          </h1>
          <p className="text-xl text-slate-300">
            Insights on education, AI, and building what's next.
          </p>
        </div>
      </section>

      {/* Blog Grid */}
      <section className="py-16 px-4 sm:px-6 lg:px-8 bg-slate-50">
        <div className="max-w-6xl mx-auto">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {blogPosts.map((post) => (
              <div key={post.id} className="bg-white rounded-lg shadow-md hover:shadow-lg transition-shadow duration-200 flex flex-col">
                <div className="p-6 flex flex-col flex-1">
                  <p className="text-sm text-slate-500 mb-2">{post.date}</p>
                  <h2
                    className="text-xl font-bold text-slate-950 mb-3 leading-snug"
                    style={{ fontFamily: "'Playfair Display', Georgia, serif" }}
                  >
                    {post.title}
                  </h2>
                  <p className="text-slate-600 text-sm leading-relaxed flex-1">
                    {formatExcerpt(post.excerpt)}
                  </p>
                  <button
                    onClick={() => togglePost(post.id)}
                    className="mt-4 inline-flex items-center gap-1 text-amber-600 font-semibold hover:text-amber-700 transition-colors text-sm"
                  >
                    {expandedId === post.id ? 'Close ↑' : 'Read More →'}
                  </button>
                </div>

                {expandedId === post.id && (
                  <div className="border-t border-slate-200 px-6 py-6">
                    <div
                      className="prose prose-slate max-w-none text-slate-700 text-sm leading-relaxed"
                      style={{ lineHeight: '1.75' }}
                      dangerouslySetInnerHTML={{ __html: post.content }}
                    />
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      </section>
    </div>
  );
}
